import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a directory to list files: ");
        String directory = reader.readLine();

        // Validate user input to only allow alphanumeric characters and specific safe characters
        if (!directory.matches("[a-zA-Z0-9/._-]+")) {
            System.err.println("Invalid input. Directory can only contain alphanumeric characters, '/', '.', '_', or '-'");
            return;
        }

        // Use ProcessBuilder to safely execute the command
        ProcessBuilder processBuilder = new ProcessBuilder("ls", directory);
        Process process = processBuilder.start();

        BufferedReader resultReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = resultReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

### Explanation:
취약유형: Command Injection
